const payload = msg.payload || {};
flow.set("telemetry", payload);
flow.set("lastTelemetryMs", Date.now());
flow.set("updated_at", payload.timestamp || new Date().toISOString());

const datasetRows = flow.get("dataset_rows") || [];
const displayLimit = Number(env.get("DISPLAY_LIMIT") || 6);
const anomalyFactor = Number(env.get("ANOMALY_FACTOR") || 1.5);
const mode = flow.get("mode") || "AUTO";
const shutdownActive = !!flow.get("shutdown_active");

const noisy = datasetRows.slice(0, Math.max(0, displayLimit - 1)).map((row) => ({
    garage_id: row.garage_id,
    value: Math.max(0, Number(row.value || 0) + Math.floor(Math.random() * 31) - 15)
}));

flow.set("others_displayed", noisy);

const meanSource = noisy.length ? noisy : datasetRows;
const mean = meanSource.length
    ? meanSource.reduce((acc, row) => acc + Number(row.value || 0), 0) / meanSource.length
    : 0;

const liveOthersMean = Number(mean.toFixed(2));
flow.set("others_mean", liveOthersMean);

const threshold = Number.isFinite(Number(payload.threshold))
    ? Number(Number(payload.threshold).toFixed(2))
    : Number((liveOthersMean * anomalyFactor).toFixed(2));

flow.set("effective_threshold", threshold);

const predictors = flow.get("garage_predictors") || {};
const evaluated = noisy.map((garage) => {
    const garageId = garage.garage_id;
    const value = Number(garage.value || 0);

    const state = predictors[garageId] || { history: [], previous_avg: null };
    const history = Array.isArray(state.history) ? state.history.slice() : [];
    history.push(value);
    if (history.length > 20) {
        history.shift();
    }

    let predictedGas = value;
    let predictedCrossing = false;

    const movingAvg = history.length
        ? history.reduce((acc, v) => acc + Number(v || 0), 0) / history.length
        : value;

    if (history.length >= 5 && state.previous_avg !== null && state.previous_avg !== undefined) {
        const growthRate = movingAvg - state.previous_avg;
        predictedGas = value + (growthRate * 150);
        predictedCrossing = predictedGas > threshold;
    }

    predictors[garageId] = {
        history,
        previous_avg: movingAvg
    };

    const anomaly = value > threshold;
    const status = anomaly ? "CRITICAL" : predictedCrossing ? "WARNING" : "SAFE";

    const fanActive = shutdownActive
        ? false
        : mode === "ON"
            ? true
            : mode === "OFF"
                ? false
                : (status === "WARNING" || status === "CRITICAL");

    return {
        garage_id: garageId,
        value,
        threshold,
        predicted_gas: Math.round(predictedGas),
        predicted_crossing: predictedCrossing,
        anomaly,
        status,
        fan_active: fanActive
    };
});

flow.set("garage_predictors", predictors);
flow.set("evaluated_other_garages", evaluated);

return msg;

