let fanStatus = context.get("fan_status") || false;
const CHAT_ID = -5156593128;

function formatTelegram(text) {
    return {
        chatId: CHAT_ID,
        type: "message",
        content: text
    };
}

if (typeof msg.payload === "string") {
    if (msg.payload === "FAN_ON") {
        context.set("manual_mode", true);
        if (!fanStatus) {
            context.set("fan_status", true);
            const out = formatTelegram(
                "**MANUAL COMMAND**\nFan ON.\nSensors ignored until AUTO command."
            );
            flow.set("latest_alert", out);
            msg.payload = out;
            return msg;
        }
        return null;
    }

    if (msg.payload === "FAN_OFF") {
        context.set("manual_mode", true);
        if (fanStatus) {
            context.set("fan_status", false);
            const out = formatTelegram(
                "**MANUAL COMMAND**\nFan OFF.\nSensors ignored until AUTO command."
            );
            flow.set("latest_alert", out);
            msg.payload = out;
            return msg;
        }
        return null;
    }

    if (msg.payload === "AUTO" || msg.payload === "AUTO_MODE") {
        context.set("manual_mode", false);
        const out = formatTelegram(
            "**AUTO MODE**\nSensor logic takes back control."
        );
        flow.set("latest_alert", out);
        msg.payload = out;
        return msg;
    }

    return null;
}

if (typeof msg.payload === "object" && msg.payload !== null) {
